    # Predict ball's future x based on vertical direction (moving down = add offset)
    if ball_y < 100:
        predicted_x = ball_x + 20  # ball moving up
    else:
        predicted_x = ball_x - 10  # ball moving down

    # Clamp prediction to valid range
    predicted_x = max(0, min(160, predicted_x))

    if predicted_x < paddle_x - 5:
        return 3  # LEFT
    elif predicted_x > paddle_x + 5:
        return 2  # RIGHT
